 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 // Train the model at startup
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

 // Load CSV and map "Yes"/"No" → bool
 var rows = File.ReadAllLines(dataPath)
     .Skip(1)
     .Where(line => !string.IsNullOrWhiteSpace(line))
     .Select(line =>
     {
         var cols = line.Split(',');
         return new CustomerData
         {
             Age = float.Parse(cols[0]),
             Income = float.Parse(cols[1]),
             Region = cols[2].Trim(),
             PurchaseHistory = float.Parse(cols[3]),
             Label = cols[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase)
         };
     })
     .ToList();

 var data = mlContext.Data.LoadFromEnumerable(rows);

 // Use cross-validation for small datasets, train/test split for larger ones
 const int crossValidationThreshold = 20;
 ITransformer model;
 DataViewSchema modelSchema;

 var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(CustomerData.Age),
         nameof(CustomerData.Income),
         "RegionEncoded",
         nameof(CustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: nameof(CustomerData.Label),
         featureColumnName: "Features"));

 if (rows.Count >= crossValidationThreshold)
 {
     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
     model = pipeline.Fit(split.TrainSet);
     modelSchema = split.TrainSet.Schema;

     var predictions = model.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(CustomerData.Label));
     Console.WriteLine($"Model trained — Accuracy: {metrics.Accuracy:F4}, AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}");
 }
 else
 {
     // Too few rows for a reliable hold-out set; train on all data
     Console.WriteLine($"Small dataset ({rows.Count} rows) — training on all data. Add more rows for train/test evaluation.");
     model = pipeline.Fit(data);
     modelSchema = data.Schema;
 }

 // Save model for PredictionEnginePool
 var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
 mlContext.Model.Save(model, modelSchema, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
 {
     var input = new CustomerData
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };
     var result = pool.Predict(input);
     return Results.Ok(new
     {
         willChurn = result.PredictedLabel,
         probability = result.Probability,
         score = result.Score
     });
 });

 app.Run();

